import { useEffect, useState } from "react";
import { useParams, useNavigate } from "react-router-dom";
import axios from "../api/axios";

export default function ReceiptPage() {
    const { bookingId } = useParams();
    const navigate = useNavigate();
    const [booking, setBooking] = useState(null);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        const fetchBooking = async () => {
            try {
                // Determine API endpoint based on role? 
                // Regular users can use /bookings/my but it returns an array.
                // Admin can use /admin/bookings.
                // We might need a specific endpoint for a single booking or filter from "myBookings".
                // For now, let's try to filter from myBookings or add a getBookingById endpoint.
                // Actually, let's add specific endpoint logic or just filter for now to be safe.
                const res = await axios.get("/bookings/my");
                const found = res.data.find(b => b._id === bookingId);

                if (found) {
                    setBooking(found);
                } else {
                    // Fallback or error
                    console.error("Booking not found in user history");
                }
                setLoading(false);
            } catch (err) {
                console.error("Error fetching receipt", err);
                setLoading(false);
            }
        };
        fetchBooking();
    }, [bookingId]);

    if (loading) return <div style={{ textAlign: "center", marginTop: "50px" }}>Loading Receipt...</div>;
    if (!booking) return <div style={{ textAlign: "center", marginTop: "50px" }}>Receipt Not Found</div>;

    // QR Data
    const qrData = JSON.stringify({
        id: booking._id,
        user: booking.userId, // ID
        vehicle: booking.vehicleNumber,
        slot: booking.slotId?.slotNumber,
        status: booking.paymentStatus
    });

    // Using a public API for QR Code generation to avoid dependencies
    const qrUrl = `https://api.qrserver.com/v1/create-qr-code/?size=200x200&data=${encodeURIComponent(qrData)}`;

    return (
        <div style={{ display: "flex", justifyContent: "center", padding: "40px", minHeight: "80vh", background: "#ecf0f1" }}>
            <div style={{ background: "white", padding: "0", borderRadius: "15px", boxShadow: "0 15px 35px rgba(0,0,0,0.1)", maxWidth: "400px", width: "100%", overflow: "hidden", position: "relative" }}>
                {/* Header */}
                <div style={{ background: "#2c3e50", padding: "20px", textAlign: "center", color: "white" }}>
                    <h2 style={{ margin: 0, fontSize: "1.5rem" }}>ParkSense Ticket</h2>
                    <p style={{ margin: "5px 0 0", opacity: 0.8, fontSize: "0.9rem" }}>Official Parking Receipt</p>
                </div>

                {/* Content */}
                <div style={{ padding: "30px", textAlign: "center" }}>
                    <img src={qrUrl} alt="Booking QR" style={{ borderRadius: "10px", border: "5px solid #2c3e50" }} />
                    <p style={{ marginTop: "15px", color: "#7f8c8d", fontSize: "0.9rem" }}>Scan this at the entry gate</p>

                    <div style={{ textAlign: "left", marginTop: "30px", borderTop: "2px dashed #eee", paddingTop: "20px" }}>
                        <DetailRow label="Vehicle No" value={booking.vehicleNumber} />
                        <DetailRow label="Location" value={booking.slotId?.parkingLotId?.name || "ParkSense Lot"} />
                        <DetailRow label="Slot" value={`#${booking.slotId?.slotNumber}`} />
                        <DetailRow label="Start Time" value={new Date(booking.startTime).toLocaleString()} />
                        <DetailRow label="End Time" value={new Date(booking.endTime).toLocaleString()} />
                        <DetailRow label="Amount Paid" value={`$${booking.amount || 10}`} bold />
                    </div>
                </div>

                {/* Footer */}
                <div style={{ background: "#f8f9fa", padding: "15px", textAlign: "center" }}>
                    <button
                        onClick={() => window.print()}
                        style={{ padding: "10px 20px", borderRadius: "5px", border: "none", background: "#3498db", color: "white", cursor: "pointer", fontWeight: "bold" }}
                    >
                        Print Receipt
                    </button>
                    <button
                        onClick={() => navigate("/")}
                        style={{ padding: "10px 20px", borderRadius: "5px", border: "none", background: "transparent", color: "#3498db", cursor: "pointer", marginLeft: "10px" }}
                    >
                        Back to Home
                    </button>
                </div>
            </div>
        </div>
    );
}

const DetailRow = ({ label, value, bold }) => (
    <div style={{ display: "flex", justifyContent: "space-between", marginBottom: "12px", fontSize: "0.95rem" }}>
        <span style={{ color: "#95a5a6" }}>{label}</span>
        <span style={{ color: "#2c3e50", fontWeight: bold ? "bold" : "normal" }}>{value}</span>
    </div>
);
